// Parse Ollama response
const response = $input.first().json;
let scriptData;

try {
  const rawText = response.response || JSON.stringify(response);
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    scriptData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in response');
  }
} catch (error) {
  // Fallback episode
  scriptData = {
    title: "The Rise of Local AI Models",
    episode_number: "auto",
    intro: "Welcome back to AI Tech Talk! Today we're diving into the exciting world of local AI models and why they're changing everything.",
    segments: [
      {
        title: "What Are Local AI Models?",
        content: "Local AI models are artificial intelligence systems that run entirely on your own hardware, without needing cloud services. Think Ollama, Llama, and other open-source models you can run on your laptop or even a Raspberry Pi. This shift represents a fundamental change in how we interact with AI.",
        duration_estimate: "2 min"
      },
      {
        title: "Privacy Benefits",
        content: "The biggest advantage? Privacy. Your data never leaves your machine. No cloud providers analyzing your prompts, no data breaches to worry about. For businesses handling sensitive information, this is revolutionary. You maintain complete control over your AI interactions.",
        duration_estimate: "2 min"
      },
      {
        title: "Cost Savings",
        content: "Running local models eliminates ongoing API costs. After the initial hardware investment, your AI usage is essentially free. For developers building AI-powered apps, this changes the entire economics of AI deployment.",
        duration_estimate: "2 min"
      }
    ],
    outro: "That's it for today's episode! If you're excited about local AI, make sure to subscribe and join us next time as we explore AI automation tools.",
    keywords: ["AI", "local models", "privacy", "ollama"],
    description: "Exploring the revolution of local AI models and why running AI on your own hardware is changing the game."
  };
}

// Add episode number based on execution count
const executionId = $execution.id || 1;
if (scriptData.episode_number === 'auto') {
  scriptData.episode_number = `EP${String(executionId).padStart(3, '0')}`;
}

return { json: scriptData };

// Combine all script segments into full narration
const scriptData = $input.first().json;

const fullScript = [
  scriptData.intro,
  ...scriptData.segments.map(seg => seg.content),
  scriptData.outro
].join('\n\n');

return {
  json: {
    ...scriptData,
    fullScript: fullScript
  }
};

// Convert base64 to binary audio
const base64Audio = $input.first().json.stdout.trim();
const scriptData = $input.first().json;

return {
  json: scriptData,
  binary: {
    audio: {
      data: base64Audio,
      mimeType: 'audio/wav',
      fileName: `${scriptData.episode_number}_${scriptData.title.replace(/\s+/g, '_')}.wav`,
      fileExtension: 'wav'
    }
  }
};

