// Generate RSS feed entry for podcast platforms
const scriptData = $('Parse Script').item.json;
const audioUrl = "https://your-domain.com/podcasts/" + scriptData.episode_number + ".mp3";

const rssEntry = `
<item>
  <title>${scriptData.title}</title>
  <description>${scriptData.description}</description>
  <pubDate>${new Date().toUTCString()}</pubDate>
  <enclosure url="${audioUrl}" type="audio/mpeg" />
  <guid>${scriptData.episode_number}</guid>
  <itunes:episode>${scriptData.episode_number.replace('EP', '')}</itunes:episode>
  <itunes:title>${scriptData.title}</itunes:title>
  <itunes:summary>${scriptData.description}</itunes:summary>
</item>
`;

return {
  json: {
    rssEntry,
    episodeData: scriptData
  }
};
